taxonomy.databases.nosql.mongo
taxonomy.databases.nosql.cassandra
taxonomy.databases.sql.mysql
taxonomy.databases.sql.postgres
taxonomy['databases']['hybrid']['orient']
 
 
 
print taxonomy.as_dict()
{ 
    "databases": {
        "hybrid": {
            "orient": {}
        }, 
        "nosql": {
            "cassandra": {}, 
            "mongo": {}
        }, 
        "sql": {
            "mysql": {}, 
            "postgres": {}
        }
    }, 
    "linguagens": {
        "funcionais": {
            "elixir": {}, 
            "f_sharp": {}
        }, 
        "script": {
            "perl": {}, 
            "python": {}
        }
    }
}
```

